import org.springframework.context.annotation.*;
import org.springframework.security.oauth2.client.*;
import org.springframework.security.oauth2.client.web.reactive.function.client.ServerOAuth2AuthorizedClientExchangeFilterFunction;
import org.springframework.web.reactive.function.client.WebClient;
import org.springframework.beans.factory.annotation.Value;

@Configuration
public class HdfcWebClientConfig {

    @Value("${hdfc.api.base-url}")
    private String hdfcBaseUrl;

    @Bean
    public WebClient hdfcWebClient(OAuth2AuthorizedClientManager authorizedClientManager) {
        // Filter function: automatically injects Authorization: Bearer <token>
        var oauth2Filter = new ServerOAuth2AuthorizedClientExchangeFilterFunction(authorizedClientManager);
        // Default to 'hdfc-api' registration for all requests from this client:
        oauth2Filter.setDefaultClientRegistrationId("hdfc-api");

        return WebClient.builder()
            .baseUrl(hdfcBaseUrl)
            .filter(oauth2Filter)
            .defaultHeader("Content-Type", "application/json")
            .build();
    }

    @Bean
    public OAuth2AuthorizedClientManager authorizedClientManager(
            ClientRegistrationRepository clientRegistrations,
            OAuth2AuthorizedClientRepository authorizedClients) {
        var manager = new DefaultOAuth2AuthorizedClientManager(
            clientRegistrations, authorizedClients);
        // Provider: handles client_credentials grant type:
        manager.setAuthorizedClientProvider(
            OAuth2AuthorizedClientProviderBuilder.builder()
                .clientCredentials()
                .build());
        return manager;
    }
}

