import org.springframework.security.oauth2.jwt.Jwt;
import org.springframework.stereotype.*;
import java.util.*;
import java.time.Instant;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import org.springframework.security.oauth2.jwt.JwtClaimNames;

@Service
public class TokenInspectorService {

    public List<String> getScopes(Jwt jwt) {
        // OAuth2 scopes can be in 'scp' or 'scope' claim:
        List<String> scopes = jwt.getClaimAsStringList("scp");
        if (scopes == null) {
            // Try space-separated string format (common in JWT):
            String scopeStr = jwt.getClaimAsString("scope");
            if (scopeStr != null) return Arrays.asList(scopeStr.split(" "));
        }
        return scopes != null ? scopes : List.of();
    }

    public boolean hasScope(Jwt jwt, String scope) {
        return getScopes(jwt).contains(scope);
    }

    public String getClientId(Jwt jwt) {
        // For Client Credentials tokens: sub = client_id
        // For Auth Code tokens: sub = user_id, azp = client_id
        String azp = jwt.getClaimAsString("azp");  // authorized party
        return azp != null ? azp : jwt.getSubject();
    }

    public boolean isExpired(Jwt jwt) {
        Instant exp = jwt.getExpiresAt();
        return exp != null && exp.isBefore(Instant.now());
    }
}

@SpringBootTest
class TokenInspectorTest {
    @Autowired TokenInspectorService svc;

    @Test void hasScope_works() {
        // Simulate a JWT with scope claim:
        org.springframework.security.oauth2.jwt.Jwt jwt =
            org.springframework.security.oauth2.jwt.Jwt.withTokenValue("token")
                .header("alg", "RS256")
                .claim("scope", "payments:read settlements:read")
                .claim("sub", "hdfc-client")
                .issuedAt(Instant.now())
                .expiresAt(Instant.now().plusSeconds(3600))
                .build();
        assertTrue(svc.hasScope(jwt, "payments:read"));
        assertFalse(svc.hasScope(jwt, "payments:write"));
        assertFalse(svc.isExpired(jwt));
    }
}

