import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.security.oauth2.jwt.Jwt;
import org.springframework.security.oauth2.server.resource.authentication.JwtAuthenticationToken;
import org.springframework.web.reactive.function.client.WebClient;
import org.springframework.stereotype.*;
import reactor.core.publisher.Mono;

@Service
public class FraudCheckService {
    private final WebClient fraudClient;

    FraudCheckService(WebClient.Builder builder) {
        this.fraudClient = builder.baseUrl("http://fraud-service.payments.svc.cluster.local").build();
    }

    public FraudScore checkFraud(String paymentId) {
        // Extract current user's JWT from SecurityContext:
        String token = getCurrentToken();

        // Forward token to fraud service (token propagation):
        return fraudClient.post()
            .uri("/api/fraud/check")
            .header("Authorization", "Bearer " + token)
            .bodyValue(new FraudRequest(paymentId))
            .retrieve()
            .bodyToMono(FraudScore.class)
            .block();
    }

    private String getCurrentToken() {
        var auth = SecurityContextHolder.getContext().getAuthentication();
        if (auth instanceof JwtAuthenticationToken jwtAuth) {
            return jwtAuth.getToken().getTokenValue();
        }
        throw new IllegalStateException("No JWT in SecurityContext");
    }

    // WHY TOKEN PROPAGATION (not Client Credentials here):
    // Payment service needs to check fraud on behalf of the MERCHANT.
    // Fraud service needs to know: which merchant is making this request?
    // Token propagation: fraud service sees the merchant's token → can enforce
    // merchant-level rate limits, audit trails, and permission checks.
    // Client Credentials: fraud service would only see 'payment-service' as caller
    // → loses the merchant identity → can't enforce per-merchant limits.

    record FraudRequest(String paymentId) {}
    record FraudScore(double score, String decision) {}
}

