@RestController
class ProfileController {
    @GetMapping("/profile")
    public java.util.Map<String,String> profile(@AuthenticationPrincipal OidcUser user) {
        // OidcUser: OIDC-specific (has id_token, userInfo claims)
        return java.util.Map.of(
            "name",  user.getFullName(),
            "email", user.getEmail(),
            "sub",   user.getSubject(),  // Google's stable user ID
            "picture", user.getPicture()
        );
    }
}

// OIDC vs plain OAuth2:
// OAuth2: authorization framework (access to resources)
// OIDC (OpenID Connect): identity layer ON TOP of OAuth2
// OIDC adds: id_token (JWT with user info) + /userinfo endpoint + standard claims
// If scope includes 'openid': OIDC flow (you get user identity)
// Without 'openid': plain OAuth2 (you get access to resources, not identity)
// For login/SSO: always use OIDC (scope=openid,email,profile)

