// TOKEN PROPAGATION STRATEGY:
// 1. order-service → risk-service: PROPAGATE user JWT
//    Risk service needs to know which merchant is making the trade
//    to enforce per-merchant risk limits.
//
// 2. risk-service → market-data-service: CLIENT CREDENTIALS
//    Market data is not user-specific (same data for all)
//    No user identity needed — just service authentication
//    Market data endpoint may not even accept user tokens

@Service
class TokenRoutingService {
    enum TokenStrategy { PROPAGATE_USER, CLIENT_CREDENTIALS }

    // Determine token strategy based on downstream service:
    TokenStrategy strategyFor(String targetService) {
        return switch(targetService) {
            case "risk-service" -> TokenStrategy.PROPAGATE_USER;  // needs merchant identity
            case "market-data-service" -> TokenStrategy.CLIENT_CREDENTIALS;  // generic data
            case "audit-service" -> TokenStrategy.PROPAGATE_USER;  // needs audit trail
            default -> TokenStrategy.CLIENT_CREDENTIALS;  // safe default
        };
    }

    String getUserToken() {
        var auth = SecurityContextHolder.getContext().getAuthentication();
        if (auth instanceof JwtAuthenticationToken jwtAuth)
            return jwtAuth.getToken().getTokenValue();
        return null;
    }
}

@SpringBootTest
class TokenRoutingTest {
    @Autowired TokenRoutingService svc;
    @Test void routingStrategy(){
        assertEquals(TokenRoutingService.TokenStrategy.PROPAGATE_USER, svc.strategyFor("risk-service"));
        assertEquals(TokenRoutingService.TokenStrategy.CLIENT_CREDENTIALS, svc.strategyFor("market-data-service"));
    }
}

