//   # Client Credentials tokens don't have refresh tokens — just request a new one

// For Client Credentials: token expiry → get a new token (no refresh token concept)
// Spring OAuth2AuthorizedClientManager handles this AUTOMATICALLY:
// - Checks token expiry before each request
// - If expired: requests new client_credentials token
// - No manual refresh needed!

@Service
class HdfcApiService {
    private static final Logger log = LoggerFactory.getLogger(HdfcApiService.class);
    private final WebClient client;  // configured with OAuth2 filter

    HdfcApiService(WebClient c){client=c;}

    public String getSettlements() {
        return client.get().uri("/settlements")
            .retrieve()
            .onStatus(status -> status.value() == 401, resp -> {
                // 401 from HDFC: token was rejected
                // Spring's OAuth2 filter should have prevented this (pre-expiry check)
                // If we get here: clock skew or token revoked externally
                log.error("Token rejected by HDFC. Possible revocation or clock skew.");
                return Mono.error(new RuntimeException("Token rejected — check auth config"));
            })
            .bodyToMono(String.class)
            .block();
    }

    // FOR REFRESH TOKENS (Auth Code flow):
    // Spring's OAuth2AuthorizedClientManager handles refresh automatically
    // when OAuth2AuthorizedClientProviderBuilder includes .refreshToken()
    // manager.setAuthorizedClientProvider(
    //   OAuth2AuthorizedClientProviderBuilder.builder()
    //     .authorizationCode()
    //     .refreshToken()  ← adds refresh capability
    //     .build());
    // On 401: Spring re-fetches using refresh_token, retries automatically
}

